function useDebounce<T>(value: T, delay: number): T {
  const [debouncedText, setDebouncedText] = useState<T>(() => value)

  useEffect(() => {
    const id = setTimeout(() => {
      setDebouncedText(value)
    }, delay)

    return () => clearTimeout(id)
  }, [value, delay])

  return debouncedText
}
